import { buildBitfabRequestHeaders } from "./clientHeaders.js";
import { getConfig } from "./config.js";
/**
 * Fire-and-forget report of a browser → CLI hand-off outcome. Emits a
 * server-side `api:plugin_handoff_delivered` analytics event so we can
 * track which delivery path (loopback / ticket / paste) is carrying load
 * across the fleet and decide when the loopback fast path is worth
 * retiring.
 *
 * Takes the api key explicitly because the login flow has it in hand
 * before `saveCredentials` has run, and `getConfig()` would miss it.
 * Never throws — telemetry must never block a successful hand-off.
 */
export async function reportHandoff(apiKey, pluginVersion, platform, body) {
    const config = getConfig();
    const headers = buildBitfabRequestHeaders(apiKey, pluginVersion, platform);
    try {
        const response = await fetch(`${config.serviceUrl}/api/plugin/analytics/handoff`, {
            method: "POST",
            headers,
            body: JSON.stringify(body),
        });
        if (config.debug && !response.ok) {
            console.error(`reportHandoff: server returned ${response.status} for ${body.flow}`);
        }
    }
    catch (err) {
        if (config.debug) {
            const message = err instanceof Error ? err.message : String(err);
            console.error(`reportHandoff: request failed for ${body.flow}: ${message}`);
        }
    }
}
